import{c as a,Q as r,j as e,m as o}from"./chunks/framework.hhGiamYR.js";const g=JSON.parse('{"title":"🏛️ 马基雅维利研究","description":"","frontmatter":{},"headers":[],"relativePath":"research/machiavelli/index.md","filePath":"research/machiavelli/index.md"}'),i={name:"research/machiavelli/index.md"};function n(l,t,s,h,d,c){return r(),e("div",null,[...t[0]||(t[0]=[o('<h1 id="🏛️-马基雅维利研究" tabindex="-1">🏛️ 马基雅维利研究 <a class="header-anchor" href="#🏛️-马基雅维利研究" aria-label="Permalink to &quot;🏛️ 马基雅维利研究&quot;">​</a></h1><p>尼科洛·马基雅维利（1469-1527），佛罗伦萨第二国务秘书、外交家、史学家、剧作家，也是西方政治思想史上最有争议的人物。他活了 58 岁，经历了共和国的兴衰、美第奇家族的复辟、入狱、流放——然后在乡下的农庄里写出了《君主论》和《论李维》，两本改变了政治思想史的书。</p><blockquote><p><em>&quot;我爱我的祖国胜过爱我的灵魂。&quot;</em> — 书信 331</p></blockquote><h2 id="这是什么" tabindex="-1">这是什么 <a class="header-anchor" href="#这是什么" aria-label="Permalink to &quot;这是什么&quot;">​</a></h2><p>这里收录了马基雅维利的 <strong>17 本著作中英双语原文</strong>、<strong>7 部学术传记研究</strong>、以及 <strong>17 条提炼的核心信条</strong>。它不是维基百科式的介绍，而是一个<strong>可检索的原文库</strong>——你可以直接按章阅读原文，也可以通过<a href="index.json">索引</a>用关键词检索全库。</p><h2 id="快速入口" tabindex="-1">快速入口 <a class="header-anchor" href="#快速入口" aria-label="Permalink to &quot;快速入口&quot;">​</a></h2><table tabindex="0"><thead><tr><th>想做什么</th><th>去哪</th></tr></thead><tbody><tr><td>快速了解他的核心思想</td><td><a href="./precepts/">17 条信条</a></td></tr><tr><td>按章阅读《君主论》</td><td><a href="./machiavelli/prince/">君主论原文</a></td></tr><tr><td>搜一句原文</td><td><a href="index.json">索引</a>（596 个文件的全文映射）</td></tr><tr><td>看现代解读</td><td><a href="./commentary/ch25-prince.html">批注：君主论第 25 章</a></td></tr><tr><td>了解他的生平</td><td><a href="./biography/">传记</a></td></tr><tr><td>读学术研究</td><td><a href="./scholarship/">学术研究</a></td></tr></tbody></table><h2 id="著作" tabindex="-1">著作 <a class="header-anchor" href="#著作" aria-label="Permalink to &quot;著作&quot;">​</a></h2><h3 id="核心著作" tabindex="-1">核心著作 <a class="header-anchor" href="#核心著作" aria-label="Permalink to &quot;核心著作&quot;">​</a></h3><ul><li><a href="./machiavelli/prince/"><strong>君主论</strong> The Prince</a> — 写于 1513 年，只有 26 章的小册子，却是政治思想史上引用最频繁的书。拿破仑圈阅批注版 + 英译版</li><li><a href="./machiavelli/discourses/"><strong>论李维</strong> Discourses on Livy</a> — 3 卷 142 章，比《君主论》更长、更复杂、更像他真正想说的</li><li><a href="./machiavelli/florentine/"><strong>佛罗伦萨史</strong> Florentine Histories</a> — 8 卷，从罗马帝国末期到洛伦佐·美第奇之死。他写的不是编年史，而是政治分析</li></ul><h3 id="实用著作" tabindex="-1">实用著作 <a class="header-anchor" href="#实用著作" aria-label="Permalink to &quot;实用著作&quot;">​</a></h3><ul><li><a href="./machiavelli/art-of-war/"><strong>兵法</strong> The Art of War</a> — 7 卷，对话录形式。马基雅维利全集版 + 英译版</li><li><a href="./machiavelli/letters/"><strong>书信集</strong> Letters</a> — 上下两卷，跨度二十年。最著名的书信 224（1513 年 12 月 10 日致韦托里）</li><li><a href="./machiavelli/diplomatic/"><strong>政务与外交著作</strong> Diplomatic Works</a> — 上下两卷，出使报告、公文、备忘录</li><li><a href="./machiavelli/drama-poetry/"><strong>戏剧·诗歌·散文</strong> Drama &amp; Poetry</a> — 含《曼陀罗》《金驴记》《十年纪》</li></ul><h2 id="核心信条" tabindex="-1">核心信条 <a class="header-anchor" href="#核心信条" aria-label="Permalink to &quot;核心信条&quot;">​</a></h2><p>从他的全部著作中提炼出 17 条核心思维方式——不是道德教条，而是十四年外交生涯 + 研读古今历史的实效法则。<a href="./precepts/">查看全部 17 条信条 →</a></p><p><strong>实效真理</strong> · <strong>狮狐之喻</strong> · <strong>机运与准备</strong> · <strong>畏惧优于爱戴</strong> · <strong>冲突的建设性</strong> · <strong>地狱胜过天堂</strong> · <strong>我是新的喀戎</strong></p><blockquote><p><em>&quot;被人畏惧比受人爱戴安全得多。人们忘记父亲之死比忘记遗产的丧失来得还要快。&quot;</em> — 君主论，第 17 章</p></blockquote>',16)])])}const p=a(i,[["render",n]]);export{g as __pageData,p as default};
